  ('dietitian-moex-00814', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '端午節正值氣候炎熱時期易導致食物變質腐敗，下列對於粽子貯藏的敘述，何者正確？', '["粽子在長期冷凍貯藏過程中，品質不會發生變化", "粽子若暫不食用，應儘速置於冷藏或冷凍貯藏，可延長食品保存期", "冷凍貯存可視為粽子殺菌的方式之一", "冷凍貯存可以完全抑制粽子內油脂之氧化酸敗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:52+00:00", "source_pdf_sha1": "1bd37038064e", "answer_pdf_sha1": "916acd229a9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00815', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '蛋白中天然存在具有破壞革蘭氏陽性菌細胞壁功能的抗菌物質為：', '["乳素（lactenins）", "苯甲酸（benzoicacid）", "溶菌素（lysozyme）", "生物素（biotin）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:52+00:00", "source_pdf_sha1": "1bd37038064e", "answer_pdf_sha1": "916acd229a9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
